// ── RNG (same as dream) ──
window.HR = {};
window.HR.rng = function(seed){
  let s = seed >>> 0;
  return () => {
    s = Math.imul(s ^ (s >>> 15), s | 1);
    s ^= s + Math.imul(s ^ (s >>> 7), s | 61);
    return ((s ^ (s >>> 14)) >>> 0) / 0xFFFFFFFF;
  };
};
window.HR.seed = function(str){
  let h = 0x811c9dc5;
  for(let i=0;i<str.length;i++){h^=str.charCodeAt(i);h=Math.imul(h,0x01000193);}
  return h>>>0;
};
window.HR.pick = function(arr,rng){ return arr[Math.floor(rng()*arr.length)]; };

