// Helper: get zodiac index from day/month
window.HR.getZodiacIdx = function(day, month) {
  const borders = [[1,20],[2,19],[3,20],[4,20],[5,21],[6,21],[7,23],[8,23],[9,23],[10,23],[11,22],[12,22]];
  let idx = month - 1;
  if(day < borders[month-1][1]) idx = (month - 2 + 12) % 12;
  return idx;
};

